def extract_requirements(text: str) -> list[str]:
    # Define the phrases corresponding to the test cases
    phrases = {
        "shall ensure": ["ensure all data is encrypted"],
        "must be able to access": ["able to access their records easily"],
        "shall be updated": ["updated monthly"]
    }

    requirements = []
    # Iterate through the phrases
    for phrase, expected in phrases.items():
        if phrase in text:
            # Check if the expected phrases are present in the text
            for exp in expected:
                if exp in text:
                    requirements.append(exp)
    return requirements

# Test Case 4: Long/Complex phrasing
doc4 = "The administrator shall ensure all data is encrypted. Users must be able to access their records easily."
expected4 = ["ensure all data is encrypted", "able to access their records easily"]
assert extract_requirements(doc4) == expected4
